const body = $input.first().json || {};

const call_id = body.call_id || '';
const call_status = body.call_status || 'unknown';
const disconnection_reason = body.disconnection_reason || 'unknown';
const call_duration_sec = body.call_length_second || 0;
const call_analysis = body.call_analysis || {};

// Retell echoes back whatever we put in retell_llm_dynamic_variables
const dynVars = body.retell_llm_dynamic_variables || {};
const lead_id = dynVars.lead_id || '';
const attempt_number = parseInt(dynVars.attempt_number || '1', 10);
const customer_name = dynVars.customer_name || 'Unknown';
const property_value = dynVars.property_value || 'undisclosed';

// Enforce contract
if (!call_id) throw new Error(`WEBHOOK_MISSING_CALL_ID: body=${JSON.stringify(body).slice(0,200)}`);
if (!lead_id) throw new Error(`WEBHOOK_MISSING_LEAD_ID: Retell did not echo back lead_id. check dynamic variables in Workflow A.`);

// OUTCOME CLASSIFICATION
// 'answered' = call ended AND the human actually picked up
// 'voicemail' = call ended but hit voicemail
// 'no_answer' = call ended, no one answered
// 'error' = retell-side error (credits, carrier reject, internal failure)
// 'unknown' = any unrecognised combination
const ANSWERED_REASONS = new Set(['user_hangup', 'agent_hangup', 'call_transfer']);
let outcome;
if (call_status === 'ended' && ANSWERED_REASONS.has(disconnection_reason)) {
  outcome = 'answered';
} else if (call_status === 'ended' && disconnection_reason === 'voicemail') {
  outcome = 'voicemail';
} else if (call_status === 'ended' && (disconnection_reason === 'no_answer' || disconnection_reason === 'dial_failed')) {
  outcome = 'no_answer';
} else if (call_status === 'error') {
  outcome = 'error'; // CRITICAL FIX #3: errors no longer route to voicemail retry loop
} else {
  outcome = 'unknown';
}

return [{ json: {
  call_id,
  call_status,
  disconnection_reason,
  call_duration_sec,
  call_summary: call_analysis.call_summary || '',
  user_sentiment: call_analysis.user_sentiment || 'unknown',
  lead_id,
  attempt_number,
  customer_name,
  property_value,
  outcome,
  received_at: new Date().toISOString()
}}];

const callData = $('Validate & Classify Call Outcome').first().json;
const crmRow = $input.first().json || {};

// Merge, preferring CRM data for lead fields (it's authoritative)
return [{ json: {
  ...callData,
  full_name: crmRow.full_name || callData.customer_name,
  email: crmRow.email || '',
  phone: crmRow.phone || '',
  lead_score: crmRow.lead_score || 0,
  lead_tier: crmRow.lead_tier || 'C',
  source: crmRow.source || 'unknown'
}}];

