const d = $input.first().json;
const next_attempt = d.attempt_number + 1;
// Attempt 1â†’2: wait 2 hours. Attempt 2â†’3: wait 24 hours.
const wait_hours = d.attempt_number === 1 ? 2 : 24;
const script_hook = next_attempt === 2 ? 'second_contact' : 'final_contact';
const attempts_exhausted = d.attempt_number >= 3;
return [{ json: { ...d, next_attempt, wait_hours, script_hook, attempts_exhausted } }];

