const raw = ($input.first().json.text || '').trim();
const lead = $('Merge Call Data + Lead Record').first().json;

let html = raw.replace(/```[a-z]*\s*/gi, '').replace(/```/g, '').trim();
const firstTag = html.indexOf('<');
if (firstTag > 0) html = html.slice(firstTag);

const hasHtml = /<[a-z][^>]*>/i.test(html);
const firstName = lead.full_name.split(' ')[0];

if (!hasHtml || html.length < 50) {
  html = `<p>Dear ${firstName},</p><p>We've been trying to connect with you regarding your property interest at the $${lead.property_value} level. We'd love to help â€” please book a time that works for you.</p>`;
}

return [{ json: { ...lead, sanitized_fallback_html: html, first_name: firstName } }];

